import React from 'react';
import { NativeModules } from 'react-native';

const InAppPurchase = NativeModules.InAppPurchase;

class PaymentModule extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      products: [],
      purchase: null,
    };
  }

  componentDidMount() {
    this.getProducts();
  }

  getProducts = async () => {
    const products = await InAppPurchase.getProducts(['product1', 'product2']);
    this.setState({ products });
  };

  purchaseProduct = async (productId) => {
    const purchase = await InAppPurchase.purchaseProduct(productId);
    this.setState({ purchase });
  };

  render() {
    return (
      <View>
        {this.state.products.map((product) => (
          <Button title={product.title} onPress={() => this.purchaseProduct(product.productId)} />
        ))}
      </View>
    );
  }
}

export default PaymentModule;